{
  "summary": "This paper proposes a novel, scalable approach to approximating human similarity judgments across image, audio, and video modalities using language-based embeddings derived from adaptive crowdsourced tags. It presents a large-scale evaluation of over 600 pre-trained models, introduces the STEP-Tag adaptive tagging pipeline, and demonstrates that combining language and sensory embeddings yields superior similarity approximations compared to existing methods.",
  "strengths": [
    {
      "point": "Comprehensive large-scale evaluation of pre-trained models across multiple modalities",
      "evidence": "Evaluated 611 pre-trained models on image, audio, and video datasets with extensive human similarity judgments."
    },
    {
      "point": "Introduction of a scalable, modality-agnostic language-based similarity approximation method",
      "evidence": "Proposed using language embeddings from LLMs and classical text methods to approximate human similarity at O(N) cost."
    },
    {
      "point": "Development and validation of the STEP-Tag adaptive tagging pipeline",
      "evidence": "STEP-Tag produced higher quality and more diverse tags than baselines, improving similarity approximation."
    },
    {
      "point": "Demonstration that stacked embeddings combining language and sensory models outperform individual methods",
      "evidence": "Stacked methods consistently provided the best approximation of human similarity across all tested modalities."
    },
    {
      "point": "Release of a large, multi-modal human similarity dataset and practical guidelines",
      "evidence": "Collected 206,339 human judgments from 1,492 participants and provided resources for replication and further research."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient discussion and comparison to prior cognitive science and NLP literature on language-based similarity",
      "evidence": "The paper lacks citations or contrasts with existing work using language embeddings to model human similarity judgments."
    },
    {
      "point": "Lack of detailed justification and ablation studies for key STEP-Tag design choices",
      "evidence": "No analysis of adaptive stopping criteria, tag diversity thresholds, or balance between tag specificity and generality."
    },
    {
      "point": "Unclear fairness of DNN baselines due to missing information on domain adaptation or fine-tuning",
      "evidence": "No clarification on whether the 611 pre-trained models were fine-tuned or adapted before similarity evaluation."
    },
    {
      "point": "Limited transparency in evaluation metrics and hyperparameter tuning",
      "evidence": "Correlation coefficients used are unspecified; tuning procedures for stacked method hyperparameters are not clearly described."
    },
    {
      "point": "Reproducibility concerns due to missing details on human judgment collection and LLM embedding extraction",
      "evidence": "No participant demographics, quality control, inter-rater reliability, or embedding extraction parameters provided."
    },
    {
      "point": "No exploration of alternative embedding fusion strategies beyond concatenation",
      "evidence": "The paper does not investigate weighted averaging, attention mechanisms, or other integration methods."
    },
    {
      "point": "Lack of analysis on the impact of tag quality, ambiguous/polysemous tags, and potential biases",
      "evidence": "No quantitative assessment of how tag specificity or noise affects similarity approximation; biases are mentioned but not analyzed."
    },
    {
      "point": "Limited discussion on generalizability beyond tested modalities and cross-lingual/cultural contexts",
      "evidence": "No empirical tests or detailed discussion on applying methods to other sensory modalities or diverse languages/cultures."
    },
    {
      "point": "No comparison with other scalable human similarity approximation methods",
      "evidence": "Alternatives like triplet comparisons, embedding elicitation, or active learning are not considered as baselines."
    },
    {
      "point": "Insufficient clarity in explaining classical text processing baselines",
      "evidence": "Implementation details, corpora, preprocessing, and parameter settings for co-occurrence, Rouge, bm25, and tf-idf are not described."
    }
  ],
  "questions": [
    {
      "question": "How do ambiguous or polysemous tags affect the accuracy of language-based similarity approximations?",
      "motivation": "Understanding this is critical to ensure robustness and alignment with human judgments, especially in multi-modal contexts."
    },
    {
      "question": "Would alternative embedding fusion methods (e.g., attention-based) improve over simple concatenation in stacked models?",
      "motivation": "Exploring this could lead to better integration of sensory and language information and improved similarity approximations."
    },
    {
      "question": "How well do the proposed language-based methods generalize to other sensory modalities or cross-cultural and low-resource language settings?",
      "motivation": "Evaluating generalizability is important for broader applicability and real-world deployment."
    },
    {
      "question": "What quality control measures and participant demographics were used during human judgment collection?",
      "motivation": "These details are essential for assessing data reliability and enabling reproducibility."
    },
    {
      "question": "Were the DNN baselines fine-tuned or adapted to the datasets, and how might this affect comparative performance?",
      "motivation": "Clarifying this is necessary to fairly interpret the relative performance of DNN and language-based methods."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
